import{_ as i,c as t,o as a,aj as s}from"./chunks/framework.Bc1W9V36.js";const g=JSON.parse('{"title":"Primitive Developer Reference","description":"","frontmatter":{},"headers":[],"relativePath":"index.md","filePath":"index.md"}'),r={name:"index.md"};function n(o,e,l,h,d,c){return a(),t("div",null,[...e[0]||(e[0]=[s(`<h1 id="primitive-developer-reference" tabindex="-1">Primitive Developer Reference <a class="header-anchor" href="#primitive-developer-reference" aria-label="Permalink to “Primitive Developer Reference”">​</a></h1><p>An <strong>exhaustive, compile-verified, dual-language</strong> cookbook for the entire <code>js-bao</code> client surface — one page per sub-API, an example for every public method, in <strong>JavaScript and Swift</strong> side by side.</p><p>This is intentionally <strong>separate from the <a href="/primitive-dev/primitive-docs/">getting-started docs</a></strong>. Those are tutorial-style and human-readable; this is dense reference that covers every conceivable sub-API without cluttering the main docs.</p><h2 id="how-to-read-this" tabindex="-1">How to read this <a class="header-anchor" href="#how-to-read-this" aria-label="Permalink to “How to read this”">​</a></h2><ul><li>Every snippet is a slice of a <strong>complete module that type-checks against the real clients</strong> (<code>js-bao-wss-client</code> / <code>js-bao</code> for TS; the vendored <code>swift-client</code> for Swift). A snippet that called a non-existent method or passed the wrong shape would fail the build — so what you see compiles.</li><li>Each method shows a <code>JavaScript | Swift</code> tab group. Click <strong>Swift</strong> to flip.</li></ul><h2 id="when-a-method-isn-t-in-both-languages" tabindex="-1">When a method isn&#39;t in both languages <a class="header-anchor" href="#when-a-method-isn-t-in-both-languages" aria-label="Permalink to “When a method isn&#39;t in both languages”">​</a></h2><p>The two clients aren&#39;t at full parity. Where they differ, the page says so explicitly:</p><div class="warning custom-block"><p class="custom-block-title">No Swift equivalent</p><p>The method exists in the JavaScript client but <strong>not</strong> the Swift client (or vice-versa). The available language is shown; the gap links to the tracking issue.</p></div><div class="tip custom-block"><p class="custom-block-title">Divergent shape</p><p>Both clients have the method, but the Swift signature/return diverges (often untyped <code>[String: Any]</code> where JS is typed). Both compile; the difference is flagged inline.</p></div><p>These callouts come straight from the <a href="https://github.com/Primitive-Labs/primitive-docs/blob/docs-parity-jun-3/swift-parity-crosswalk.md" target="_blank" rel="noreferrer">JS↔Swift parity crosswalk</a>.</p><h2 id="build-verify" tabindex="-1">Build &amp; verify <a class="header-anchor" href="#build-verify" aria-label="Permalink to “Build &amp; verify”">​</a></h2><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pnpm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> dev-docs:dev</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">            # serve this site locally</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pnpm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> compile:dev-examples</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">    # type-check every snippet (ts + swift) against the real clients</span></span></code></pre></div>`,12)])])}const f=i(r,[["render",n]]);export{g as __pageData,f as default};
